"use client";
import React, { useState, useEffect } from "react";
import { SearchIcon, UserIcon } from "./icons";

const Header = () => {
 const [scrolled, setScrolled] = useState(false);

 useEffect(() => {
  const handleScroll = () => setScrolled(window.scrollY > 10);
  window.addEventListener("scroll", handleScroll, { passive: true });
  return () => window.removeEventListener("scroll", handleScroll);
 }, []);

 return (
  <header
   className={`h-[68px] sticky top-0 z-[100] transition-all duration-500 px-6 xl:px-10 flex items-center gap-8 ${scrolled ? "glass-header" : "bg-white border-b border-black/[0.05]"
    }`}
  >
   {/* Brand Logotype */}
   <div className="flex flex-col select-none cursor-pointer shrink-0">
    <span
     style={{
      fontFamily: "var(--font-manrope, sans-serif)",
      fontSize: "18px",
      fontWeight: 800,
      letterSpacing: "-0.05em",
      lineHeight: "0.85",
      color: "var(--fg-main)",
     }}
    >
     СМЫСЛ
    </span>
    <span
     style={{
      fontFamily: "var(--font-manrope, sans-serif)",
      fontSize: "18px",
      fontWeight: 800,
      letterSpacing: "-0.05em",
      lineHeight: "0.85",
      color: "var(--fg-main)",
     }}
    >
     ЕСТЬ
    </span>
   </div>

   {/* Search */}
   <div className="flex-1 max-w-[480px] mx-auto">
    <div className="search-field">
     <SearchIcon size={18} className="text-[var(--fg-faint)] shrink-0 transition-colors group-focus-within:text-[var(--accent)]" />
     <input
      type="text"
      placeholder="Поиск хлеба, круассанов, выпечки..."
      className="flex-1 bg-transparent border-none px-3 outline-none"
      style={{
       fontFamily: "var(--font-manrope, sans-serif)",
       fontSize: "13px",
       fontWeight: 400,
       color: "var(--fg-main)",
      }}
     />
    </div>
   </div>

   {/* Profile */}
   <div className="flex items-center gap-1 shrink-0">
    <button
     className="h-10 px-3 rounded-xl flex items-center gap-2.5 transition-all duration-200"
     style={{ color: "var(--fg-muted)" }}
     onMouseEnter={e => (e.currentTarget.style.background = "rgba(0,0,0,0.04)")}
     onMouseLeave={e => (e.currentTarget.style.background = "transparent")}
    >
     <UserIcon size={22} />
     <div className="hidden lg:flex flex-col items-start leading-none gap-[3px]">
      <span
       style={{
        fontFamily: "var(--font-manrope, sans-serif)",
        fontSize: "10px",
        fontWeight: 800,
        letterSpacing: "0.12em",
        textTransform: "uppercase",
        color: "var(--fg-faint)",
       }}
      >
       Профиль
      </span>
      <span
       style={{
        fontFamily: "var(--font-manrope, sans-serif)",
        fontSize: "13px",
        fontWeight: 700,
        color: "var(--fg-main)",
        letterSpacing: "-0.01em",
       }}
      >
       Войти
      </span>
     </div>
    </button>
   </div>
  </header>
 );
};

export default Header;
