"use client";
import React from "react";
import { MinusIcon, PlusIcon } from "./icons";
import { CartItem } from "@/app/page";

interface Props {
 cart: CartItem[];
 onUpdateQuantity: (id: number, delta: number) => void;
 total: number;
}

const CartSidebar: React.FC<Props> = ({ cart, onUpdateQuantity, total }) => {
 return (
  <div className="flex flex-col h-full bg-white border-l border-black/[0.05] reveal-anim">

   {/* Header */}
   <div className="px-7 pt-7 pb-5 border-b border-black/[0.05]">
    <div className="flex items-center justify-between mb-4">
     <h2
      style={{
       fontFamily: "var(--font-manrope, sans-serif)",
       fontSize: "20px",
       fontWeight: 800,
       letterSpacing: "-0.03em",
       color: "var(--fg-main)",
      }}
     >
      Корзина
     </h2>
     {cart.length > 0 && (
      <span
       style={{
        fontFamily: "var(--font-manrope, sans-serif)",
        fontSize: "11px",
        fontWeight: 800,
        letterSpacing: "0.05em",
        background: "#F0F0F5",
        color: "var(--fg-muted)",
        padding: "3px 9px",
        borderRadius: "100px",
       }}
      >
       {cart.reduce((s, i) => s + i.quantity, 0)} шт
      </span>
     )}
    </div>

    {/* Delivery row */}
    <div
     className="flex items-center gap-3 p-3.5 cursor-pointer rounded-xl transition-all duration-200"
     style={{ background: "var(--bg-soft)", border: "1px solid var(--border-faint)" }}
     onMouseEnter={e => (e.currentTarget.style.background = "#EDECF4")}
     onMouseLeave={e => (e.currentTarget.style.background = "var(--bg-soft)")}
    >
     <span className="flex-shrink-0 w-2 h-2 rounded-full bg-green-500" style={{ boxShadow: "0 0 0 3px rgba(34,197,94,0.15)" }} />
     <div className="flex-1 min-w-0">
      <p
       style={{
        fontFamily: "var(--font-manrope, sans-serif)",
        fontSize: "13px",
        fontWeight: 700,
        color: "var(--fg-main)",
        letterSpacing: "-0.01em",
       }}
       className="truncate"
      >
       ул. Академика Янгеля
      </p>
      <p
       style={{
        fontFamily: "var(--font-manrope, sans-serif)",
        fontSize: "10px",
        fontWeight: 800,
        letterSpacing: "0.1em",
        textTransform: "uppercase",
        color: "#16a34a",
        marginTop: "2px",
       }}
      >
       Доставим за 15 минут
      </p>
     </div>
     <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" style={{ color: "var(--fg-faint)", flexShrink: 0 }}>
      <path d="m6 9 6 6 6-6" />
     </svg>
    </div>
   </div>

   {/* Items */}
   <div className="flex-1 overflow-y-auto px-7 py-5 space-y-5">
    {cart.length === 0 ? (
     <div className="h-full flex flex-col items-center justify-center text-center py-16" style={{ opacity: 0.45 }}>
      <div
       className="w-20 h-20 flex items-center justify-center mb-5"
       style={{ background: "var(--bg-soft)", borderRadius: "28px" }}
      >
       <span style={{ fontSize: "36px" }}>🥐</span>
      </div>
      <p
       style={{
        fontFamily: "var(--font-manrope, sans-serif)",
        fontSize: "15px",
        fontWeight: 800,
        color: "var(--fg-main)",
        letterSpacing: "-0.02em",
       }}
      >
       Корзина пуста
      </p>
      <p
       style={{
        fontFamily: "var(--font-manrope, sans-serif)",
        fontSize: "12px",
        fontWeight: 500,
        color: "var(--fg-muted)",
        marginTop: "6px",
        lineHeight: "1.5",
        maxWidth: "180px",
       }}
      >
       Добавьте что-нибудь вкусное из каталога
      </p>
     </div>
    ) : (
     cart.map((item) => (
      <div key={item.id} className="flex gap-3 group">
       {/* Image */}
       <div
        className="w-[68px] h-[68px] flex-shrink-0 flex items-center justify-center rounded-[14px] overflow-hidden transition-colors duration-300"
        style={{
         background: "var(--bg-soft)",
         border: "1px solid var(--border-faint)",
        }}
       >
        {item.image ? (
         <img
          src={item.image}
          alt={item.name}
          className="w-[80%] h-[80%] object-contain mix-blend-multiply"
         />
        ) : (
         <span style={{ fontSize: "28px" }}>🍞</span>
        )}
       </div>

       {/* Info */}
       <div className="flex-1 min-w-0 flex flex-col justify-between py-0.5">
        <p
         className="line-clamp-2 leading-snug"
         style={{
          fontFamily: "var(--font-manrope, sans-serif)",
          fontSize: "13px",
          fontWeight: 600,
          color: "var(--fg-main)",
          letterSpacing: "-0.01em",
         }}
        >
         {item.name}
        </p>

        <div className="flex items-center justify-between mt-2">
         {/* Qty control */}
         <div className="cart-qty-ctrl">
          <button onClick={() => onUpdateQuantity(item.id, -1)} aria-label="Убрать">
           <MinusIcon size={10} />
          </button>
          <span className="qty-value">{item.quantity}</span>
          <button onClick={() => onUpdateQuantity(item.id, 1)} aria-label="Добавить">
           <PlusIcon size={10} />
          </button>
         </div>

         {/* Line total */}
         <span
          style={{
           fontFamily: "var(--font-manrope, sans-serif)",
           fontSize: "15px",
           fontWeight: 800,
           letterSpacing: "-0.03em",
           color: "var(--fg-main)",
          }}
         >
          {item.price * item.quantity} ₽
         </span>
        </div>
       </div>
      </div>
     ))
    )}
   </div>

   {/* Footer */}
   <div
    className="px-7 pt-5 pb-7"
    style={{
     borderTop: "1px solid var(--border-faint)",
     background: "white",
     boxShadow: "0 -12px 32px rgba(0,0,0,0.03)",
    }}
   >
    {/* Breakdown */}
    <div className="space-y-2.5 mb-6">
     <div className="flex justify-between">
      <span
       style={{
        fontFamily: "var(--font-manrope, sans-serif)",
        fontSize: "13px",
        fontWeight: 500,
        color: "var(--fg-muted)",
       }}
      >
       Подитог
      </span>
      <span
       style={{
        fontFamily: "var(--font-manrope, sans-serif)",
        fontSize: "13px",
        fontWeight: 700,
        color: "var(--fg-sub)",
        letterSpacing: "-0.01em",
       }}
      >
       {total} ₽
      </span>
     </div>
     <div className="flex justify-between">
      <span
       style={{
        fontFamily: "var(--font-manrope, sans-serif)",
        fontSize: "13px",
        fontWeight: 500,
        color: "var(--fg-muted)",
       }}
      >
       Доставка
      </span>
      <span
       style={{
        fontFamily: "var(--font-manrope, sans-serif)",
        fontSize: "13px",
        fontWeight: 700,
        color: "#16a34a",
       }}
      >
       Бесплатно
      </span>
     </div>

     {/* Divider */}
     <div style={{ height: "1px", background: "var(--border-faint)", marginTop: "4px" }} />

     <div className="flex justify-between items-baseline pt-1">
      <span
       style={{
        fontFamily: "var(--font-manrope, sans-serif)",
        fontSize: "14px",
        fontWeight: 700,
        color: "var(--fg-sub)",
       }}
      >
       Итого
      </span>
      <span
       style={{
        fontFamily: "var(--font-manrope, sans-serif)",
        fontSize: "28px",
        fontWeight: 800,
        letterSpacing: "-0.04em",
        color: "var(--fg-main)",
       }}
      >
       {total} ₽
      </span>
     </div>
    </div>

    <button className="checkout-btn group" disabled={cart.length === 0}>
     <span>К оформлению</span>
     <svg
      width="18" height="18" viewBox="0 0 24 24" fill="none"
      stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"
      className="group-hover:translate-x-1.5 transition-transform duration-300"
     >
      <path d="M5 12h14M12 5l7 7-7 7" />
     </svg>
    </button>

    <p
     className="text-center mt-4"
     style={{
      fontFamily: "var(--font-manrope, sans-serif)",
      fontSize: "10px",
      fontWeight: 700,
      letterSpacing: "0.1em",
      textTransform: "uppercase",
      color: "var(--fg-faint)",
      opacity: 0.6,
     }}
    >
     Безопасная оплата
    </p>
   </div>
  </div>
 );
};

export default CartSidebar;
